interface.pattern:
@LitmusKtTest
class TenantContextIsolationTest {
  @Scenario(threads = [2, 4, 8, 16])
  fun `tenant context isolated between threads`() {
    // Thread 1: Set tenant-a context
    thread1 {
      TenantContext.setCurrentTenantId("tenant-a")
      val retrieved = TenantContext.getCurrentTenantId()
      assert(retrieved == "tenant-a")
    }

    // Thread 2: Set tenant-b context
    thread2 {
      TenantContext.setCurrentTenantId("tenant-b")
      val retrieved = TenantContext.getCurrentTenantId()
      assert(retrieved == "tenant-b")
    }

    // Validate: No cross-thread contamination
    // LitmusKt detects if contexts leak between threads
  }
}

@LitmusKtTest
class EventProcessorPropagationTest {
  @Scenario(threads = [4, 8])
  fun `async event processors receive correct tenant context`() {
    // Thread 1: Dispatch event for tenant-a
    thread1 {
      val event = createEventWithMetadata("tenant-a")
      eventBus.publish(event)
    }

    // Thread 2: Dispatch event for tenant-b
    thread2 {
      val event = createEventWithMetadata("tenant-b")
      eventBus.publish(event)
    }

    // Async Processor: Validate correct context restored
    asyncProcessor {
      val tenantId = TenantContext.getCurrentTenantId()
      // LitmusKt validates: tenantId matches event metadata (no race)
    }
  }
}

@LitmusKtTest
class ConnectionPoolContextTest {
  @Scenario(threads = [8, 16])
  fun `connection pool does not leak tenant context`() {
    // Multiple threads use pooled connections
    parallel(threads = 8) { threadId ->
      val tenantId = "tenant-$threadId"
      TenantContext.setCurrentTenantId(tenantId)

      // Execute query (uses pooled connection)
      val widgets = widgetRepository.findAll()

      // Validate: Query filtered by current tenant (no leak)
      widgets.forEach { widget ->
        assert(widget.tenantId == tenantId)
      }

      TenantContext.clearCurrentTenant()
    }

    // LitmusKt detects: Connection pool leaking context between threads
  }
}
